import{_ as d,o as r,c as o,a2 as n}from"./chunks/framework.Bjylvv1V.js";const c=JSON.parse('{"title":"용어 사전","description":"","frontmatter":{},"headers":[],"relativePath":"guide/glossary.md","filePath":"guide/glossary.md","lastUpdated":1771991831000}'),a={name:"guide/glossary.md"};function s(e,t,g,h,l,b){return r(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="용어-사전" tabindex="-1">용어 사전 <a class="header-anchor" href="#용어-사전" aria-label="Permalink to &quot;용어 사전&quot;">​</a></h1><p>XpERP에서 사용하는 주요 용어를 쉽게 설명합니다. 회계·아파트 관리 용어가 낯설다면 이 페이지를 참고하세요.</p><div class="tip custom-block"><p class="custom-block-title">찾는 방법</p><p>브라우저에서 <code>Ctrl + F</code>를 눌러 원하는 용어를 검색하세요.</p></div><h2 id="ᄀ" tabindex="-1">ㄱ <a class="header-anchor" href="#ᄀ" aria-label="Permalink to &quot;ㄱ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>용어</th><th>쉬운 설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>가수금</strong></td><td>누구에게서 온 돈인지 아직 확인되지 않은 입금. 확인 후 해당 세대 수납으로 처리</td><td>통장에 150,000원 입금됐는데 입금자를 모를 때</td></tr><tr><td><strong>감가상각</strong></td><td>시설·장비의 가치가 시간이 지나면서 줄어드는 것을 회계에 반영</td><td>엘리베이터 교체 비용을 매년 나눠서 비용 처리</td></tr><tr><td><strong>감면</strong></td><td>특정 조건(복지, 장애 등)에 해당하는 세대의 요금을 줄여주는 것</td><td>기초생활수급자 전기요금 감면</td></tr><tr><td><strong>검침</strong></td><td>전기, 수도, 가스 등 계량기의 수치를 읽어 사용량을 산정하는 작업</td><td>매월 1~2주차에 각 세대 계량기를 읽음</td></tr><tr><td><strong>결산</strong></td><td>일정 기간의 수입과 지출을 정리하여 재무 상태를 확정하는 작업</td><td>12월 말에 연간 결산을 실행</td></tr><tr><td><strong>계정과목</strong></td><td>돈의 이동을 분류하는 이름표. 수입/지출/자산/부채 등으로 구분</td><td>보통예금, 관리비수입, 수선유지비, 미수금 등</td></tr><tr><td><strong>고지서</strong></td><td>세대에 관리비를 알려주는 문서</td><td>매월 발송하는 관리비 고지서</td></tr><tr><td><strong>공용부분</strong></td><td>아파트에서 모든 입주민이 함께 사용하는 공간</td><td>복도, 엘리베이터, 주차장, 놀이터</td></tr><tr><td><strong>관리비</strong></td><td>아파트 공용부분의 유지관리 및 운영에 필요한 비용</td><td>일반관리비, 청소비, 경비비, 수선유지비 등</td></tr><tr><td><strong>관리비부과</strong></td><td>산정된 관리비를 각 세대에 청구하는 작업</td><td>매월 3주차에 관리비를 부과</td></tr><tr><td><strong>관리비예치금</strong></td><td>입주 시 납부하는 보증금 성격의 관리비. 전출 시 환급</td><td>선수관리비라고도 함</td></tr><tr><td><strong>관리외수입</strong></td><td>관리비 외에 발생하는 수입</td><td>주차장 외부 개방 수입, 광고 수입</td></tr><tr><td><strong>귀속 연월</strong></td><td>해당 급여나 세금이 속하는 기간</td><td>3월 급여의 귀속 연월은 2026년 3월</td></tr></tbody></table><h2 id="ᄂ" tabindex="-1">ㄴ <a class="header-anchor" href="#ᄂ" aria-label="Permalink to &quot;ㄴ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>용어</th><th>쉬운 설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>난방검침</strong></td><td>세대별 난방 사용량을 검침하는 작업</td><td>열량계 또는 유량계 지침 읽기</td></tr><tr><td><strong>납부기한</strong></td><td>관리비를 납부해야 하는 마감 날짜</td><td>보통 다음 달 말일</td></tr></tbody></table><h2 id="ᄃ" tabindex="-1">ㄷ <a class="header-anchor" href="#ᄃ" aria-label="Permalink to &quot;ㄷ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>용어</th><th>쉬운 설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>단지</strong></td><td>관리 대상이 되는 아파트 단지</td><td>○○아파트</td></tr><tr><td><strong>대변</strong></td><td>회계에서 돈이 나가거나 부채가 생기는 쪽. &quot;주는 쪽&quot;</td><td>관리비 수입 발생 → 대변에 기록</td></tr><tr><td><strong>대차대조표</strong></td><td>특정 시점의 자산, 부채, 자본을 한눈에 보여주는 표</td><td>12월 31일 기준 재무 상태</td></tr><tr><td><strong>독촉장</strong></td><td>미납 세대에 납부를 요청하는 공식 문서</td><td>3개월 이상 미납 시 경고 독촉장 발송</td></tr><tr><td><strong>동별</strong></td><td>아파트 동(棟) 단위로 구분하여 처리하는 방식</td><td>101동, 102동별 관리비 집계</td></tr></tbody></table><h2 id="ᄆ" tabindex="-1">ㅁ <a class="header-anchor" href="#ᄆ" aria-label="Permalink to &quot;ㅁ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>용어</th><th>쉬운 설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>마감</strong></td><td>해당 월(또는 연도)의 회계를 끝내고 확정하는 것. 마감 후 수정 제한</td><td>3월 31일에 3월 회계 마감</td></tr><tr><td><strong>미납</strong></td><td>납부 기한까지 관리비를 납부하지 않은 상태</td><td>3월 관리비를 4월 말까지 안 낸 경우</td></tr><tr><td><strong>미수금</strong></td><td>부과했지만 아직 받지 못한 돈</td><td>관리비를 부과했는데 아직 안 낸 금액</td></tr><tr><td><strong>미지급금</strong></td><td>서비스를 받았지만 아직 지급하지 않은 돈</td><td>청소 용역비를 아직 안 준 경우</td></tr><tr><td><strong>민원</strong></td><td>입주민이 관리사무소에 요청하는 사항</td><td>수도 고장, 주차 민원, 소음 민원</td></tr></tbody></table><h2 id="ᄇ" tabindex="-1">ㅂ <a class="header-anchor" href="#ᄇ" aria-label="Permalink to &quot;ㅂ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>용어</th><th>쉬운 설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>바우처 할인</strong></td><td>에너지 바우처(복지 대상) 금액을 관리비에서 차감</td><td>한국지역난방공사 에너지바우처 할인</td></tr><tr><td><strong>발생금액</strong></td><td>해당 항목의 총 비용 (세대별 배분 전 금액)</td><td>공용전기료 총액 500만원</td></tr><tr><td><strong>별도금액</strong></td><td>자동 계산이 아닌 수동으로 추가/차감하는 금액</td><td>인테리어 공사 보증금 추가 부과</td></tr><tr><td><strong>보조부원장</strong></td><td>특정 계정과목의 세부 거래 내역을 기록한 장부</td><td>미수금 보조부원장 → 세대별 미수금 내역</td></tr><tr><td><strong>보통예금</strong></td><td>은행 보통예금 계좌. 관리비 수납·지출에 사용</td><td>관리비 수납 통장</td></tr><tr><td><strong>부과</strong></td><td>관리비를 산정하여 각 세대에 청구하는 것</td><td>매월 3주차에 부과 처리</td></tr><tr><td><strong>부과그룹</strong></td><td>관리비를 다르게 적용하는 세대 묶음</td><td>일반세대, 상가세대 등 그룹 구분</td></tr><tr><td><strong>부과기초작업</strong></td><td>월별 부과의 기본 틀(기간·납부기한)을 설정하는 작업</td><td>부과처리 전에 반드시 실행</td></tr><tr><td><strong>부가세(VAT)</strong></td><td>부가가치세. 물건/서비스 가격의 10%</td><td>100만원 공급가에 부가세 10만원</td></tr><tr><td><strong>분개</strong></td><td>거래를 차변과 대변으로 나누어 기록하는 것</td><td>관리비 수납: 차변(보통예금), 대변(미수금)</td></tr><tr><td><strong>분리검침</strong></td><td>공용/전용 사용량을 분리하여 검침하는 것</td><td>상가와 주거 분리 검침</td></tr><tr><td><strong>분리부과</strong></td><td>입주자/사업자/소유자별로 관리비를 나눠 부과하는 것</td><td>상가 입주 단지에서 2분리 또는 3분리</td></tr></tbody></table><h2 id="ᄉ" tabindex="-1">ㅅ <a class="header-anchor" href="#ᄉ" aria-label="Permalink to &quot;ㅅ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>용어</th><th>쉬운 설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>4대보험</strong></td><td>건강보험, 국민연금, 고용보험, 산재보험</td><td>급여에서 공제되는 보험료</td></tr><tr><td><strong>세금계산서</strong></td><td>사업자 간 거래 시 부가세 포함 금액을 증빙하는 문서</td><td>용역비 지급 시 세금계산서 수취</td></tr><tr><td><strong>세대</strong></td><td>아파트의 각 가구 단위</td><td>101동 501호 = 1세대</td></tr><tr><td><strong>세입세출서</strong></td><td>예산 대비 실제 수입/지출을 비교하는 보고서</td><td>연말 결산 시 예산 집행률 확인</td></tr><tr><td><strong>선수금</strong></td><td>미리 받은 돈. 아직 서비스를 제공하지 않은 상태</td><td>다음 달 관리비를 미리 낸 경우</td></tr><tr><td><strong>손익계산서</strong></td><td>일정 기간의 수입과 지출, 이익/손실을 보여주는 표</td><td>1월~12월 관리비 수입 vs 운영 지출</td></tr><tr><td><strong>수납</strong></td><td>부과된 관리비를 수령/처리하는 작업</td><td>자동이체·창구 납부 등으로 수납</td></tr><tr><td><strong>수선유지비</strong></td><td>시설을 수리·유지하는 데 드는 비용</td><td>엘리베이터 수리비, 배관 교체비</td></tr><tr><td><strong>시산표</strong></td><td>모든 계정과목의 차변/대변 합계를 모아 일치 여부를 확인하는 표</td><td>차변 합계 = 대변 합계여야 정상</td></tr></tbody></table><h2 id="ᄋ" tabindex="-1">ㅇ <a class="header-anchor" href="#ᄋ" aria-label="Permalink to &quot;ㅇ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>용어</th><th>쉬운 설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>연말정산</strong></td><td>1년간 원천징수한 소득세를 정산하여 환급/추징하는 절차</td><td>매년 1~2월 직원 연말정산</td></tr><tr><td><strong>연체료</strong></td><td>납부기한을 넘겨 추가로 부과되는 금액</td><td>1개월 연체 시 연체율 적용</td></tr><tr><td><strong>예산</strong></td><td>회계연도의 수입/지출 계획</td><td>연초에 수립하는 연간 예산</td></tr><tr><td><strong>예치금</strong></td><td>입주 시 납부하는 관리비 보증금 (= 관리비예치금)</td><td>전출 시 환급</td></tr><tr><td><strong>원천징수</strong></td><td>급여 지급 시 소득세를 미리 떼어 국가에 납부하는 것</td><td>매월 급여에서 소득세 공제</td></tr><tr><td><strong>월마감</strong></td><td>해당 월의 회계를 종료하고 수정을 제한하는 것</td><td>마감 후 전표 입력/수정 불가</td></tr><tr><td><strong>이월</strong></td><td>이전 기간의 잔액을 다음 기간으로 넘기는 것</td><td>년도이월: 전년도 잔액 → 금년도 기초잔액</td></tr><tr><td><strong>입주</strong></td><td>새로운 소유자/임차인이 세대에 입주하는 것</td><td>신규 입주자 등록</td></tr><tr><td><strong>일계표</strong></td><td>하루 동안의 모든 거래를 계정과목별로 집계한 표</td><td>일별 차변/대변 합계 확인</td></tr><tr><td><strong>일할 계산</strong></td><td>월 중간 입주/퇴거 시 날짜 비율로 금액을 나누는 것</td><td>15일 거주 = 관리비 × 15/30</td></tr></tbody></table><h2 id="ᄌ" tabindex="-1">ㅈ <a class="header-anchor" href="#ᄌ" aria-label="Permalink to &quot;ㅈ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>용어</th><th>쉬운 설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>자동분개</strong></td><td>자주 사용하는 전표 패턴을 미리 등록해 자동으로 불러오는 기능</td><td>매월 동일한 용역비 전표를 자동 생성</td></tr><tr><td><strong>자동이체</strong></td><td>은행 계좌에서 관리비가 자동으로 출금되는 납부 방식</td><td>매월 25일 자동이체 출금</td></tr><tr><td><strong>장기수선계획</strong></td><td>아파트 공용부분의 장기적인 수선 계획</td><td>외벽 도색(5년 주기), 엘리베이터 교체(15년)</td></tr><tr><td><strong>장기수선충당금</strong></td><td>장기수선계획에 따른 수선비용을 충당하기 위해 매월 적립하는 금액</td><td>세대별 매월 일정액 적립, 전출 시 환급</td></tr><tr><td><strong>장부</strong></td><td>거래 내역을 기록한 회계 문서의 총칭</td><td>총계정원장, 보조부원장, 현금출납장 등</td></tr><tr><td><strong>적요</strong></td><td>전표에 기록하는 거래에 대한 간단한 설명</td><td>&quot;3월 관리비 수납&quot;, &quot;엘리베이터 수리비&quot;</td></tr><tr><td><strong>전자결재</strong></td><td>문서의 결재를 전자적으로 처리하는 시스템</td><td>지출결의서 → 결재 → 이체 실행</td></tr><tr><td><strong>전출</strong></td><td>기존 소유자/임차인이 세대에서 퇴거하는 것</td><td>전출 시 중간정산 필요</td></tr><tr><td><strong>전표</strong></td><td>회계 거래를 기록하는 문서. 차변과 대변으로 구성</td><td>입금전표, 출금전표, 대체전표</td></tr><tr><td><strong>전월지침</strong></td><td>전월 검침 시 기록한 계량기 수치</td><td>당월 사용량 = 당월지침 - 전월지침</td></tr><tr><td><strong>제예금명세서</strong></td><td>모든 예금 계좌의 잔액을 정리한 표</td><td>통장 대사 시 시스템 잔액 확인용</td></tr><tr><td><strong>조견표</strong></td><td>관리비 산정 기준표. 면적, 세대수 등에 따른 부과 기준</td><td>주차비 조견표: 1대당 월 30,000원</td></tr><tr><td><strong>중간정산</strong></td><td>월 중간에 전출 시 거주 일수만큼 관리비를 정산하는 것</td><td>15일 거주 시 관리비 절반 정산</td></tr><tr><td><strong>지급명세서</strong></td><td>직원에게 지급한 소득 내역을 세무서에 신고하는 문서</td><td>근로소득 지급명세서 (다음 해 3월 10일까지 제출)</td></tr><tr><td><strong>지출결의서</strong></td><td>지출을 승인받기 위한 결재 문서</td><td>수선비 지출결의서 → 결재 → 이체</td></tr></tbody></table><h2 id="ᄎ" tabindex="-1">ㅊ <a class="header-anchor" href="#ᄎ" aria-label="Permalink to &quot;ㅊ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>용어</th><th>쉬운 설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>차변</strong></td><td>회계에서 돈이 들어오거나 자산이 늘어나는 쪽. &quot;받는 쪽&quot;</td><td>관리비 미수금 발생 → 차변에 기록</td></tr><tr><td><strong>차량관리</strong></td><td>단지 내 차량 등록 및 관리</td><td>입주 시 차량 등록, 전출 시 해제</td></tr><tr><td><strong>체납</strong></td><td>납부기한이 지난 미납 관리비</td><td>3개월 이상 체납 시 독촉장 발송</td></tr><tr><td><strong>추경예산</strong></td><td>연중에 당초 예산을 수정하는 것</td><td>예상치 못한 대규모 수선 발생 시</td></tr><tr><td><strong>충당금</strong></td><td>미래에 사용할 목적으로 미리 적립하는 돈</td><td>장기수선충당금, 퇴직급여충당금</td></tr></tbody></table><h2 id="ᄐ" tabindex="-1">ㅌ <a class="header-anchor" href="#ᄐ" aria-label="Permalink to &quot;ㅌ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>용어</th><th>쉬운 설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>통장 대사</strong></td><td>실제 통장 잔액과 시스템(장부) 잔액이 일치하는지 확인하는 작업</td><td>매월 마감 전 필수</td></tr><tr><td><strong>퇴직정산</strong></td><td>퇴직 직원의 급여 및 퇴직금 정산</td><td>근속 기간에 따른 퇴직금 계산</td></tr></tbody></table><h2 id="ᄑ" tabindex="-1">ㅍ <a class="header-anchor" href="#ᄑ" aria-label="Permalink to &quot;ㅍ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>용어</th><th>쉬운 설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>부분수납</strong></td><td>관리비 전액이 아닌 일부만 납부하는 것</td><td>30만원 중 20만원만 납부</td></tr></tbody></table><h2 id="ᄒ" tabindex="-1">ㅎ <a class="header-anchor" href="#ᄒ" aria-label="Permalink to &quot;ㅎ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>용어</th><th>쉬운 설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>현금출납장</strong></td><td>현금의 입금·출금·잔액을 기록한 장부</td><td>일별 현금 흐름 확인</td></tr><tr><td><strong>홈택스</strong></td><td>국세청 온라인 세금 신고 시스템 (www.hometax.go.kr)</td><td>원천징수 신고, 연말정산 제출</td></tr><tr><td><strong>환급</strong></td><td>초과 납부한 세금 등을 돌려받는 것</td><td>연말정산 결과 환급금 발생</td></tr><tr><td><strong>회계기수</strong></td><td>회계연도 단위. 보통 1년(1월~12월)</td><td>제5기 = 5번째 회계연도</td></tr><tr><td><strong>회계전표</strong></td><td>= 전표. 모든 거래를 차변/대변으로 기록한 문서</td><td>입금전표, 출금전표, 대체전표</td></tr></tbody></table><h2 id="차변과-대변-쉽게-이해하기" tabindex="-1">차변과 대변 쉽게 이해하기 <a class="header-anchor" href="#차변과-대변-쉽게-이해하기" aria-label="Permalink to &quot;차변과 대변 쉽게 이해하기&quot;">​</a></h2><p>모든 회계 거래는 **차변(왼쪽)**과 **대변(오른쪽)**으로 기록합니다.</p><table tabindex="0"><thead><tr><th>상황</th><th>차변 (받는 쪽)</th><th>대변 (주는 쪽)</th></tr></thead><tbody><tr><td>관리비를 부과했을 때</td><td>미수금 (받을 돈 생김)</td><td>관리비수입 (수입 발생)</td></tr><tr><td>관리비를 수납했을 때</td><td>보통예금 (통장에 돈 들어옴)</td><td>미수금 (받을 돈 줄어듦)</td></tr><tr><td>용역비를 지급했을 때</td><td>관리용역비 (비용 발생)</td><td>보통예금 (통장에서 돈 나감)</td></tr><tr><td>사무용품을 구매했을 때</td><td>소모품비 (비용 발생)</td><td>보통예금 (통장에서 돈 나감)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">핵심 규칙</p><p><strong>차변 합계 = 대변 합계</strong>가 항상 같아야 합니다. 같지 않으면 전표를 저장할 수 없습니다.</p></div>',31)])])}const u=d(a,[["render",s]]);export{c as __pageData,u as default};
